@app.route('/status')
def auction_status():
    auctions = load_auctions()
    auctions_context = []
    for a in auctions:
        # Calculate time_remaining as difference between end_time and current time in a simple string format
        try:
            end_dt = datetime.strptime(a['end_time'], '%Y-%m-%d %H:%M')
            now_dt = datetime.now()
            delta = end_dt - now_dt
            if delta.total_seconds() < 0:
                time_remaining = 'Ended'
            else:
                days = delta.days
                hours = delta.seconds // 3600
                minutes = (delta.seconds % 3600) // 60
                time_remaining = f'{days}d {hours}h {minutes}m'
        except Exception:
            time_remaining = 'Unknown'

        auctions_context.append({
            'auction_id': a['auction_id'],
            'item_name': a['item_name'],
            'status': a['status'],
            'time_remaining': time_remaining,
            'current_bid': a['current_bid'],
        })
    return render_template('status.html', auctions=auctions_context)


